```python
from collections import deque

class Stack:
    def __init__(self):
        """Initializes the stack"""
        self.stack = deque()

    def is_empty(self):
        """Checks if the stack is empty. Returns True if empty, False otherwise."""
        return len(self.stack) == 0

    def push(self, item):
        """Pushes an item onto the stack."""
        self.stack.append(item)

    def pop(self):
        """Pops and returns the top item from the stack. Raises IndexError if the stack is empty."""
        return self.stack.pop()

    def peek(self):
        """Returns the top item from the stack without popping it. Raises IndexError if the stack is empty."""
        return self.stack[-1]
